// Target interface expected by the client
class Target {
  request() {
    return 'Target: default behavior';
  }
}

// Adaptee has an incompatible interface
class Adaptee {
  specificRequest() {
    return '.eetpadA eht fo roivaheb laicepS';
  }
}

// Adapter makes Adaptee compatible with the Target interface
class Adapter extends Target {
  #adaptee;

  constructor(adaptee) {
    super();
    this.#adaptee = adaptee;
  }

  request() {
    const reversed = this.#adaptee.specificRequest().split('').reverse().join('');
    return `Adapter: (TRANSLATED) ${reversed}`;
  }
}

// Client code works with any Target-compatible object
function clientCode(target) {
  console.log(target.request());
}

const target = new Target();
clientCode(target);
// Target: default behavior

const adaptee = new Adaptee();
const adapter = new Adapter(adaptee);
clientCode(adapter);
// Adapter: (TRANSLATED) Special behavior of the Adaptee.

